/**
 * pi-ci — CI pipeline wrapper.
 *
 * Provides single, plan, review, and supervised execution modes.
 */

import type { CIEvent, CIOptions, CIPipelineMode, ExitCode, TestSummary } from "../types.ts";
import { EXIT_CODES } from "../types.ts";
import { HeadlessOrchestrator, type OrchestratorHooks } from "../headless/orchestrator.ts";
import { loadAnswers } from "../headless/answer-injector.ts";
import { parseTestResults } from "./test-runner.ts";
import { generateReport } from "./report.ts";

export interface PipelineResult {
  exitCode: ExitCode;
  events: CIEvent[];
  report: string;
  testSummary?: TestSummary;
}

export class CIPipeline {
  private readonly options: CIOptions;
  private readonly hooks: OrchestratorHooks;

  constructor(options: CIOptions, hooks: OrchestratorHooks) {
    this.options = options;
    this.hooks = hooks;
  }

  /**
   * Execute the pipeline in the configured mode.
   */
  async execute(): Promise<PipelineResult> {
    switch (this.options.mode) {
      case "single":
        return this.executeSingle();
      case "plan":
        return this.executePlan();
      case "review":
        return this.executeReview();
      case "supervised":
        return this.executeSupervised();
      default:
        throw new Error(`Unknown CI pipeline mode: ${this.options.mode as string}`);
    }
  }

  /**
   * Single task mode — run one prompt to completion.
   */
  private async executeSingle(): Promise<PipelineResult> {
    const answers = await this.loadAnswers();
    const orchestrator = new HeadlessOrchestrator(answers, this.options, this.hooks);
    const result = await orchestrator.run(this.options.prompt, "single");

    return {
      exitCode: result.exitCode,
      events: result.events,
      report: generateReport(result.events),
    };
  }

  /**
   * Plan mode — execute steps from a plan file.
   *
   * Each step becomes a sequential orchestrator invocation. If any step fails,
   * the pipeline stops.
   */
  private async executePlan(): Promise<PipelineResult> {
    const allEvents: CIEvent[] = [];
    let finalExitCode: ExitCode = EXIT_CODES.SUCCESS;
    let totalDuration = 0;

    // Plan steps are provided via the executeStep hook — the orchestrator
    // iterates over steps internally.
    const answers = await this.loadAnswers();
    const orchestrator = new HeadlessOrchestrator(answers, this.options, this.hooks);
    const result = await orchestrator.run(this.options.prompt, "plan");

    allEvents.push(...result.events);
    finalExitCode = result.exitCode;
    totalDuration = result.durationMs;

    return {
      exitCode: finalExitCode,
      events: allEvents,
      report: generateReport(allEvents),
    };
  }

  /**
   * PR review mode — review a PR by number.
   */
  private async executeReview(): Promise<PipelineResult> {
    const answers = await this.loadAnswers();
    const orchestrator = new HeadlessOrchestrator(answers, this.options, this.hooks);
    const prompt = this.options.prNumber
      ? `Review PR #${this.options.prNumber}`
      : this.options.prompt;
    const result = await orchestrator.run(prompt, "single");

    return {
      exitCode: result.exitCode,
      events: result.events,
      report: generateReport(result.events),
    };
  }

  /**
   * Supervised mode — stdin/stdout forwarding for an external orchestrator.
   */
  private async executeSupervised(): Promise<PipelineResult> {
    const answers = await this.loadAnswers();
    const orchestrator = new HeadlessOrchestrator(answers, this.options, this.hooks);
    const result = await orchestrator.run(this.options.prompt, "single");

    return {
      exitCode: result.exitCode,
      events: result.events,
      report: generateReport(result.events),
    };
  }

  private async loadAnswers() {
    if (this.options.answersFile) {
      return loadAnswers(this.options.answersFile);
    }
    return [];
  }
}

/**
 * pi-ci — Test result parsing for TAP, Jest, and Vitest output formats.
 */

import type { TestSummary } from "../types.ts";

export type TestOutputFormat = "tap" | "jest" | "vitest";

/**
 * Parse test output and return a summary.
 */
export function parseTestResults(output: string, format: TestOutputFormat): TestSummary {
  if (!output || !output.trim()) {
    return { passed: 0, failed: 0, total: 0, duration_ms: 0 };
  }

  switch (format) {
    case "tap":
      return parseTap(output);
    case "jest":
      return parseJest(output);
    case "vitest":
      return parseVitest(output);
    default:
      return { passed: 0, failed: 0, total: 0, duration_ms: 0 };
  }
}

/**
 * Parse TAP (Test Anything Protocol) output.
 *
 * Example:
 *   1..5
 *   ok 1 - first test
 *   not ok 2 - failing test
 *   ok 3 - third test
 */
function parseTap(output: string): TestSummary {
  let passed = 0;
  let failed = 0;

  const lines = output.split("\n");
  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.startsWith("ok ")) {
      passed++;
    } else if (trimmed.startsWith("not ok ")) {
      failed++;
    }
  }

  return {
    passed,
    failed,
    total: passed + failed,
    duration_ms: 0, // TAP doesn't have standard duration
  };
}

/**
 * Parse Jest-style test output.
 *
 * Looks for patterns like:
 *   Tests:       5 passed, 2 failed, 7 total
 *   Time:        3.456 s
 */
function parseJest(output: string): TestSummary {
  let passed = 0;
  let failed = 0;
  let total = 0;
  let durationMs = 0;

  // Match test summary line
  const testMatch = output.match(
    /Tests:\s*(\d+)\s*passed(?:,\s*(\d+)\s*failed)?(?:,\s*(\d+)\s*total)?/,
  );
  if (testMatch) {
    passed = parseInt(testMatch[1], 10);
    failed = parseInt(testMatch[2] || "0", 10);
    total = parseInt(testMatch[3] || String(passed + failed), 10);
  } else {
    // Fallback: count individual test lines
    const passMatches = output.match(/✓|PASS/g);
    const failMatches = output.match(/✕|FAIL/g);
    passed = passMatches?.length ?? 0;
    failed = failMatches?.length ?? 0;
    total = passed + failed;
  }

  // Match time
  const timeMatch = output.match(/Time:\s*([\d.]+)\s*s/);
  if (timeMatch) {
    durationMs = Math.round(parseFloat(timeMatch[1]) * 1000);
  }

  return { passed, failed, total, duration_ms: durationMs };
}

/**
 * Parse Vitest-style test output.
 *
 * Looks for patterns like:
 *   Tests  5 passed | 2 failed (7)
 *   Duration  3.45s
 */
function parseVitest(output: string): TestSummary {
  let passed = 0;
  let failed = 0;
  let total = 0;
  let durationMs = 0;

  // Match test summary line: "Tests  5 passed | 2 failed (7)"
  const testMatch = output.match(
    /Tests\s+(\d+)\s+passed(?:\s*\|\s*(\d+)\s+failed)?(?:\s*\((\d+)\))?/,
  );
  if (testMatch) {
    passed = parseInt(testMatch[1], 10);
    failed = parseInt(testMatch[2] || "0", 10);
    total = parseInt(testMatch[3] || String(passed + failed), 10);
  }

  // Match duration: "Duration  3.45s"
  const durMatch = output.match(/Duration\s+([\d.]+)s/);
  if (durMatch) {
    durationMs = Math.round(parseFloat(durMatch[1]) * 1000);
  }

  return { passed, failed, total, duration_ms: durationMs };
}

/**
 * pi-ci — PR creation via the GitHub CLI (`gh`).
 *
 * Wraps `gh pr create` with structured error handling.
 */

import { execFile } from "node:child_process";
import type { PROptions, PRResult } from "../types.ts";

/**
 * Create a pull request using the `gh` CLI.
 *
 * Throws if `gh` is not installed or the command fails.
 */
export async function createPR(options: PROptions): Promise<PRResult> {
  const args = ["pr", "create", "--title", options.title];

  if (options.body) {
    args.push("--body", options.body);
  }
  if (options.base) {
    args.push("--base", options.base);
  }
  if (options.head) {
    args.push("--head", options.head);
  }
  if (options.draft) {
    args.push("--draft");
  }
  for (const label of options.labels ?? []) {
    args.push("--label", label);
  }

  const output = await runGh(args);

  // Parse the PR URL from the output
  const urlMatch = output.match(/https:\/\/github\.com\/[^\s]+\/pull\/(\d+)/);
  if (!urlMatch) {
    throw new Error(`Failed to parse PR URL from gh output: ${output}`);
  }

  return {
    url: urlMatch[0],
    number: parseInt(urlMatch[1], 10),
  };
}

/**
 * Detect the default (base) branch for the current repository.
 */
export async function detectBaseBranch(): Promise<string> {
  const output = await runGh(["repo", "view", "--json", "defaultBranchRef", "--jq", ".defaultBranchRef.name"]);
  return output.trim() || "main";
}

/**
 * Execute a `gh` command and return stdout.
 */
function runGh(args: string[]): Promise<string> {
  return new Promise((resolve, reject) => {
    execFile("gh", args, { timeout: 60_000 }, (err, stdout, stderr) => {
      if (err) {
        const message = stderr?.trim() || err.message;
        if (err.code === "ENOENT") {
          reject(new Error("gh CLI is not installed. Install it from https://cli.github.com"));
        } else {
          reject(new Error(`gh ${args.join(" ")} failed: ${message}`));
        }
        return;
      }
      resolve(stdout);
    });
  });
}

/**
 * pi-ci — CI report generation.
 *
 * Produces JSONL or human-readable summary reports from collected CI events.
 */

import type { CIEvent, CIEndEvent, CICostEvent, CITestEvent } from "../types.ts";
import { isCIEndEvent, isCICostEvent, isCITestEvent } from "../headless/jsonl-stream.ts";

export interface ReportOptions {
  format: "jsonl" | "summary";
}

/**
 * Generate a report from a list of CI events.
 */
export function generateReport(events: CIEvent[], options?: ReportOptions): string {
  const format = options?.format ?? "jsonl";

  if (format === "summary") {
    return generateSummary(events);
  }

  // JSONL: one event per line
  return events.map((e) => JSON.stringify(e)).join("\n");
}

/**
 * Generate a human-readable summary.
 */
function generateSummary(events: CIEvent[]): string {
  const lines: string[] = ["=== CI Run Summary ===", ""];

  let totalTestsPassed = 0;
  let totalTestsFailed = 0;
  let totalCostUsd = 0;
  let exitCode = -1;
  let durationMs = 0;

  for (const event of events) {
    if (isCITestEvent(event)) {
      totalTestsPassed += event.passed;
      totalTestsFailed += event.failed;
    }
    if (isCICostEvent(event)) {
      totalCostUsd += event.cost_usd;
    }
    if (isCIEndEvent(event)) {
      exitCode = event.exit_code;
      durationMs = event.duration_ms;
    }
  }

  lines.push(`Exit Code: ${exitCode}`);
  lines.push(`Duration:  ${(durationMs / 1000).toFixed(1)}s`);
  lines.push(`Tests:     ${totalTestsPassed} passed, ${totalTestsFailed} failed`);
  if (totalCostUsd > 0) {
    lines.push(`Cost:      $${totalCostUsd.toFixed(4)}`);
  }

  const status = exitCode === 0 ? "SUCCESS" : exitCode === 10 ? "BLOCKED" : exitCode === 11 ? "CANCELLED" : "ERROR";
  lines.push(`Status:    ${status}`);

  return lines.join("\n");
}

/**
 * pi-ci — Headless orchestrator.
 *
 * Ties together exit codes, answer injection, idle detection, and JSONL
 * streaming into a single execution loop.
 */

import type { ExitCode, CIEvent, CIOptions } from "../types.ts";
import { EXIT_CODES } from "../types.ts";
import { resolveExitCode } from "./exit-codes.ts";
import { matchAnswer, type AnswerEntry } from "./answer-injector.ts";
import { IdleDetector } from "./idle-detector.ts";
import { CIEventCollector, writeCIEvent } from "./jsonl-stream.ts";
import type { Writable } from "node:stream";

export interface OrchestratorResult {
  exitCode: ExitCode;
  events: CIEvent[];
  durationMs: number;
}

export interface OrchestratorHooks {
  /** Called for each step of execution. Return a status string to signal completion. */
  executeStep: (
    prompt: string,
    injectAnswer: (question: string) => string | undefined,
  ) => Promise<StepResult>;
  /** Optional writable for JSONL streaming. */
  outputStream?: Writable;
}

export interface StepResult {
  status: string;
  edits?: { file: string; lines_added: number; lines_removed: number }[];
  tests?: { command: string; passed: number; failed: number }[];
  cost?: { tokens: *** input: number; output: number }; cost_usd: number };
}

const RESTART_CONFIG = {
  baseDelayMs: 5_000,
  maxDelayMs: 30_000,
  backoffMultiplier: 2,
};

export class HeadlessOrchestrator {
  private readonly collector = new CIEventCollector();
  private readonly answers: AnswerEntry[];
  private readonly idleTimeoutMs: number;
  private readonly maxRetries: number;
  private readonly hooks: OrchestratorHooks;

  constructor(
    answers: AnswerEntry[],
    options: CIOptions,
    hooks: OrchestratorHooks,
  ) {
    this.answers = answers;
    this.idleTimeoutMs = options.idleTimeoutMs ?? 15_000;
    this.maxRetries = options.maxRetries ?? 3;
    this.hooks = hooks;
  }

  /**
   * Run the orchestrator loop.
   *
   * 1. Emit ci_start
   * 2. Execute steps via the hook, checking for answer injection
   * 3. On idle timeout → retry with exponential backoff
   * 4. Emit ci_end with the resolved exit code
   */
  async run(prompt: string, mode: "single" | "plan"): Promise<OrchestratorResult> {
    const startTime = Date.now();

    const startEvent: CIEvent = {
      type: "ci_start",
      timestamp: new Date().toISOString(),
      task: prompt,
      mode,
    };
    this.emit(startEvent);

    let lastExitCode: ExitCode = EXIT_CODES.ERROR;
    let retries = 0;

    while (retries <= this.maxRetries) {
      const result = await this.runAttempt(prompt);
      lastExitCode = result;

      if (lastExitCode === EXIT_CODES.SUCCESS) break;
      if (lastExitCode === EXIT_CODES.BLOCKED || lastExitCode === EXIT_CODES.CANCELLED) break;

      // Retry on error/timeout
      retries++;
      if (retries <= this.maxRetries) {
        const delay = Math.min(
          RESTART_CONFIG.baseDelayMs *
            Math.pow(RESTART_CONFIG.backoffMultiplier, retries - 1),
          RESTART_CONFIG.maxDelayMs,
        );
        await sleep(delay);
      }
    }

    const durationMs = Date.now() - startTime;
    const endEvent: CIEvent = {
      type: "ci_end",
      timestamp: new Date().toISOString(),
      exit_code: lastExitCode,
      duration_ms: durationMs,
    };
    this.emit(endEvent);

    return {
      exitCode: lastExitCode,
      events: this.collector.all(),
      durationMs,
    };
  }

  /**
   * Single attempt: run with idle detection.
   */
  private async runAttempt(prompt: string): Promise<ExitCode> {
    return new Promise<ExitCode>((resolve) => {
      let settled = false;

      const idle = new IdleDetector({
        idleTimeoutMs: this.idleTimeoutMs,
        onTimeout: () => {
          if (!settled) {
            settled = true;
            resolve(EXIT_CODES.TIMEOUT);
          }
        },
      });

      const injectAnswer = (question: string): string | undefined => {
        idle.reset();
        return matchAnswer(this.answers, question);
      };

      idle.start();

      this.hooks
        .executeStep(prompt, injectAnswer)
        .then((stepResult) => {
          if (!settled) {
            settled = true;
            idle.stop();

            // Emit detail events
            if (stepResult.edits) {
              for (const edit of stepResult.edits) {
                this.emit({
                  type: "ci_edit",
                  timestamp: new Date().toISOString(),
                  file: edit.file,
                  lines_added: edit.lines_added,
                  lines_removed: edit.lines_removed,
                });
              }
            }
            if (stepResult.tests) {
              for (const t of stepResult.tests) {
                this.emit({
                  type: "ci_test",
                  timestamp: new Date().toISOString(),
                  command: t.command,
                  passed: t.passed,
                  failed: t.failed,
                });
              }
            }
            if (stepResult.cost) {
              this.emit({
                type: "ci_cost",
                timestamp: new Date().toISOString(),
                tokens: ***,
                cost_usd: stepResult.cost.cost_usd,
              });
            }

            resolve(resolveExitCode(stepResult.status));
          }
        })
        .catch(() => {
          if (!settled) {
            settled = true;
            idle.stop();
            resolve(EXIT_CODES.ERROR);
          }
        });
    });
  }

  private emit(event: CIEvent): void {
    this.collector.emit(event);
    if (this.hooks.outputStream) {
      writeCIEvent(this.hooks.outputStream, event);
    }
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise((r) => setTimeout(r, ms));
}

/**
 * pi-ci — /ci status command handler.
 *
 * Shows the status of the current or last CI run.
 */

import { CIEventCollector } from "../headless/jsonl-stream.ts";
import { generateReport } from "../ci/report.ts";
import type { CIEvent, CIEndEvent, ExitCode } from "../types.ts";
import { isCIEndEvent } from "../headless/jsonl-stream.ts";

export interface CIRunRecord {
  id: string;
  startTime: string;
  events: CIEvent[];
  exitCode?: ExitCode;
  durationMs?: number;
}

/**
 * Simple in-memory registry of CI runs (for the status command).
 */
const runRegistry = new Map<string, CIRunRecord>();

/**
 * Register a CI run for status lookups.
 */
export function registerRun(record: CIRunRecord): void {
  runRegistry.set(record.id, record);
}

/**
 * Clear all registered runs (useful for testing).
 */
export function clearRuns(): void {
  runRegistry.clear();
}

/**
 * Get a specific run by ID (prefix match supported).
 */
export function getRun(id: string): CIRunRecord | undefined {
  // Exact match first
  if (runRegistry.has(id)) {
    return runRegistry.get(id);
  }
  // Prefix match
  for (const [key, value] of runRegistry) {
    if (key.startsWith(id)) {
      return value;
    }
  }
  return undefined;
}

/**
 * Handle the /ci status command.
 *
 * Returns a human-readable status string.
 */
export function ciStatusHandler(args: unknown): string {
  const runId = typeof args === "string" ? args : undefined;

  if (runId) {
    const run = getRun(runId);
    if (!run) {
      return `No CI run found matching: ${runId}`;
    }
    return formatRunStatus(run);
  }

  // Show all runs
  if (runRegistry.size === 0) {
    return "No CI runs found.";
  }

  const lines: string[] = [];
  for (const run of runRegistry.values()) {
    lines.push(formatRunStatus(run));
    lines.push("");
  }
  return lines.join("\n").trimEnd();
}

function formatRunStatus(run: CIRunRecord): string {
  const lines: string[] = [];
  lines.push(`Run:       ${run.id}`);
  lines.push(`Started:   ${run.startTime}`);

  const endEvent = run.events.find((e): e is CIEndEvent => isCIEndEvent(e));
  if (endEvent) {
    lines.push(`Exit Code: ${endEvent.exit_code}`);
    lines.push(`Duration:  ${(endEvent.duration_ms / 1000).toFixed(1)}s`);

    const status =
      endEvent.exit_code === 0
        ? "SUCCESS"
        : endEvent.exit_code === 10
          ? "BLOCKED"
          : endEvent.exit_code === 11
            ? "CANCELLED"
            : "ERROR";
    lines.push(`Status:    ${status}`);
  } else {
    lines.push("Status:    RUNNING");
  }

  return lines.join("\n");
}

/**
 * Create a CI run tracker that collects events and registers the run.
 */
export function createRunTracker(runId: string): {
  collector: CIEventCollector;
  finalize: () => CIRunRecord;
} {
  const collector = new CIEventCollector();
  const startTime = new Date().toISOString();

  return {
    collector,
    finalize() {
      const events = collector.all();
      const endEvent = events.find((e): e is CIEndEvent => isCIEndEvent(e));
      const record: CIRunRecord = {
        id: runId,
        startTime,
        events,
        exitCode: endEvent?.exit_code,
        durationMs: endEvent?.duration_ms,
      };
      registerRun(record);
      return record;
    },
  };
}

